"""
MKT Original Commentary — 1 Timothy chapter 6 (20 new entries; v15 already present)
Run: python3 scripts/zc-original-1timothy-6-6.py

Key translation decisions:
- autarkeia (v6): 'contentment / self-sufficiency' — the Stoic philosophical term
  that Paul regrounds in godliness rather than inner virtue
- porizmos (v5): 'means of profit/livelihood' — financial gain from religion
- logomachias (v4): 'word-battles' — a hapax legomenon; disputes about nothing
- ō anthrōpe theou (v11): 'O man of God' — an OT prophetic title
- agōnizou ton kalon agōna (v12): athletic/military contest idiom
- parathēkē (v20): legal-banking term for a deposit entrusted for safekeeping
- epiphaneia (v14): 'appearing' — the distinctive Pastoral Epistle Christological term
- gnōsis pseudōnymos (v20): 'falsely named knowledge' — the errorists' gnosis claim
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "6": {
    "1": '<p><em>Hosoi eisin hypo zygon douloi</em> (all who are under the yoke of slavery): <em>hypo zygon</em> (under the yoke) — an agricultural metaphor for the condition of the enslaved; the yoke evokes the heavy labor of draft animals. The instruction is addressed to slaves with non-believing masters (v.1) and then with believing masters (v.2), showing the community included both configurations. The rationale for respectful conduct is explicitly missional: so that <em>to onoma tou theou kai hē didaskalia mē blasphēmētai</em> (God\'s name and the teaching may not be slandered). The gospel\'s credibility in the wider Greco-Roman society is the reason for the social conduct requirement.</p>',
    "2": '<p><em>Mē kataphroneitsōsan hoti adelphoi eisin, alla mallon douleuetsōsan hoti pistoi eisin kai agapētoi hoi tēs euergesias antilambanos</em> (let them not despise them because they are brothers, but serve them more fully because those who receive the benefit are faithful and beloved): the instruction counterintuitively does not say \'brothers are equals, so the slave relationship dissolves\' but \'brothers are even more worthy of full service.\'  <em>Euergesia</em> (benefit, good service) and <em>antilambanos</em> (receiving, taking hold of) — the benefactor vocabulary suggests that the believing master\'s gracious reception of service should motivate increased diligence rather than exploitation of the relationship.</p>',
    "3": '<p><em>Ei tis heterodidaskalei kai mē proserchetai hygiainousi logois tois tou Kyriou hēmōn Iēsou Christou</em> (if anyone teaches otherwise and does not agree with the sound words of our Lord Jesus Christ): <em>heterodidaskalei</em> (teaches otherwise/different things) — the same verb as 1:3; the false teacher is defined negatively by deviation from apostolic teaching. <em>Hygianousin logois</em> (sound/healthy words) — <em>hygianō</em> (to be healthy) applied to teaching is characteristic of the Pastoral Epistles (1 Tim 1:10; 6:3; Tit 1:9; 2:1; 2 Tim 1:13; 4:3); teaching is either healthy or diseased. <em>Kata eusebeian</em> (according to godliness) — the standard against which teaching is measured is practical godliness, not abstract correctness.</p>',
    "4": '<p><em>Tetyphōtai, mēden epistamenos, alla nosōn peri zētēseis kai logomachias</em> (he is conceited, knowing nothing, but being diseased about controversies and word-battles): <em>tetyphōtai</em> (is conceited/has been made smoke-blind) — the perfect passive of <em>typhōō</em> (to cloud with smoke/vapor); the false teacher is intellectually blinded by self-inflation. <em>Nosōn</em> (being diseased/sick) — <em>noseō</em> extended from physical illness to intellectual-moral disorder; the false teacher is pathologically attracted to controversies. <em>Logomachias</em> (word-battles) — a hapax legomenon in the NT; <em>logomachia</em> = battles over words with no substantive content.</p>',
    "5": '<p><em>Porizmon einai tēn eusebeian</em> (godliness as a means of profit/livelihood): <em>porizmos</em> (profit, financial gain, means of livelihood) — a commercial term; the false teachers have turned religious activity into a revenue stream. The charge of mercenary religion is a standard polemical accusation in the Greco-Roman world (Cynics, sophists, and Jewish teachers were all accused of teaching for money). Paul\'s charge is not that the teachers receive support (cf. 5:17-18: elders worthy of double honor) but that they have made financial gain the motivating goal of their teaching.</p>',
    "6": '<p><em>Estin de porizmos megas hē eusebeia meta autarkeias</em> (but godliness with contentment/self-sufficiency is great gain): the letter reverses the false teachers\' equation. <em>Autarkeia</em> (contentment, self-sufficiency) — a core Stoic philosophical virtue: the wise person who is <em>autarkēs</em> is independent of external circumstances, sufficient within themselves through cultivated virtue. Paul adopts the Stoic vocabulary but regrounds it: godliness (relation to God) rather than inner virtue is the source of true sufficiency. The Stoic goal of <em>autarkeia</em> is fulfilled not by philosophical training but by godliness (cf. Phil 4:11: Paul has \'learned\' <em>autarkein</em> through union with Christ).</p>',
    "7": '<p><em>Ouden gar eisēnegkamen eis ton kosmon, hoti ouden dynametha kai exenegkein</em> (for we brought nothing into the world, and we are unable to take anything out of it): the universally recognized truth about human mortality and possessionlessness. The closest parallels are Job 1:21 (\'naked I came from my mother\'s womb, and naked I will depart\') and Eccles 5:15 (\'as they came from their mother\'s womb, so they will depart\'). The maxim grounds the sufficiency-with-godliness teaching in the ontological reality of human existence: accumulation has no ultimate future.</p>',
    "8": '<p><em>Echontes de diatrophas kai skepas, toutois arskesthēsometha</em> (but having food and clothing, we will be content with these): <em>diatrophas</em> (food, sustenance) and <em>skepas</em> (covering, shelter/clothing) — the two basic physical necessities. The pairing echoes Stoic and Cynic diatribes on the minimal requirements for a life of virtue, and also the wisdom tradition (Prov 30:8: \'Give me neither poverty nor riches\'). The conditional minimal sufficiency — if we have these, we will be content — is the practical application of <em>autarkeia</em> grounded in godliness.</p>',
    "9": '<p><em>Hoi de boulomenoi ploutein empipto<br>usin eis peirasmon kai pagida</em> (those who want to get rich fall into temptation and a trap): the participial phrase <em>boulomenoi ploutein</em> (wanting to get rich) identifies the posture of wealth-craving, not wealth itself, as the danger. <em>Peirasmon kai pagida</em> (temptation and trap) — two images: the internal testing that pulls toward what destroys, and the external snare of the trapper. <em>Epithumias pollas anōētous kai blaberas, hai bythi<br>zousi tous anthrōpous eis olethron kai apōleian</em> (many foolish and harmful desires that plunge people into ruin and destruction) — <em>bythizousi</em> (to plunge/sink, literally submerge) is a nautical term for sinking a ship.</p>',
    "10": '<p><em>Rhiza gar pantōn tōn kakōn estin hē philarguria</em> (for a root of all the evils is the love of money): <em>philarguria</em> (love of money/silver; <em>philos</em> + <em>argyros</em>) — the Pastoral Epistles\' formulation is often misquoted as \'money is the root of all evil\'; the actual claim is that love of money is <em>a</em> root of all kinds of evil (not <em>the</em> root of <em>all</em> evil without qualification). The Greco-Roman moralist tradition had similar formulations. <em>Hēs tines oregomenoi</em> (craving which some have) — <em>oregomai</em> (to reach out for, crave) is a different verb from <em>epithumia</em> (desire), suggesting the active reaching-out for what one does not yet possess. <em>Apeplanethesan apo tēs pisteōs kai heautous periepeiran odynais pollais</em> (have wandered from the faith and pierced themselves with many pains) — <em>periepeiran</em> (pierced through, impaled) is a vivid self-inflicted wound image.</p>',
    "11": '<p><em>Sy de, ō anthrōpe theou, tauta pheuge</em> (but you, O man of God, flee these things): <em>anthrōpe theou</em> (man of God) — an OT prophetic title applied to Moses (Deut 33:1), Samuel (1 Sam 9:6-8), Elijah (1 Kgs 17:18, 24), Elisha (2 Kgs 4:9), and other prophets; its application to Timothy elevates him to the prophetic tradition of covenant loyalty and counter-cultural faithfulness. <em>Diōke de dikaiosynēn, eusebeian, pistin, agapēn, hypomonēn, prautēta</em> (pursue righteousness, godliness, faith, love, endurance, gentleness) — the six-term virtue list balances the flight from vice (v.11a) with the pursuit of virtue; <em>diōkō</em> (pursue) is the same verb used for persecution, implying active energetic pursuit.</p>',
    "12": '<p><em>Agōnizou ton kalon agōna tēs pisteōs</em> (fight/contend the good contest/fight of faith): the athletic and military contest vocabulary (<em>agōnizomai</em>, <em>agōn</em>) is concentrated in the Pastoral Epistles and elsewhere in Paul (Col 1:29; 4:12; Phil 1:30; 2:16; 1 Cor 9:25-27). <em>Epilaboū tēs aiōniou zōēs, eis hēn eklēthēs kai hōmologēsas tēn kalēn homologian enōpion pollōn martyrōn</em> (take hold of eternal life, to which you were called and confessed the good confession before many witnesses): <em>homologian</em> (confession, declaration of agreement) — probably a baptismal or ordination confession; <em>enōpion pollōn martyrōn</em> (before many witnesses) suggests a public liturgical context.</p>',
    "13": '<p><em>Parangellō soi enōpion tou theou tou zōogonountos ta panta kai Christou Iēsou tou martyrēsantos epi Pontiou Pilatou tēn kalēn homologian</em> (I charge you before God who gives life to all things and Christ Jesus who testified the good confession before Pontius Pilate): <em>zōogonountos ta panta</em> (who gives life to all things) — the Creator-God as the ground of the solemn charge; the one who gives all life is the witness. Pontius Pilate (<em>epi Pontiou Pilatou</em>) — one of the rare explicit historical datings in the Pastoral Epistles (26-36 CE); Christ\'s testimony before Pilate (<em>martyrēsas tēn kalēn homologian</em>) is the paradigm for Timothy\'s public confession. The parallel between Christ\'s testimony before Pilate and Timothy\'s confession before witnesses (v.12) is structurally deliberate.</p>',
    "14": '<p><em>Tērēsai se tēn entolēn aspilon anepilēmpton mechri tēs epiphaneias tou Kyriou hēmōn Iēsou Christou</em> (to keep the command without spot and unimpeachable until the appearing of our Lord Jesus Christ): <em>tēn entolēn</em> (the commandment) — the singular may refer to the whole body of apostolic instruction or specifically the charge given to Timothy. <em>Aspilon anepilēmpton</em> (without spot, unimpeachable) — the dual compound is near-liturgical; the language echoes sacrificial purity requirements (amōmos = without blemish, Heb 9:14) and judicial acquittal language. <em>Epiphaneia</em> (appearing) — the Pastoral Epistles\' distinctive Christological term (2 Tim 1:10; 4:1, 8; Tit 2:13; cf. 2 Thess 2:8), used for both the first coming (2 Tim 1:10) and the Parousia. It is also the Hellenistic technical term for the manifestation of a deity or the public appearance of a king.</p>',
    "16": '<p><em>Ho monos echōn athanasian, phōs oikōn aprositon, hon eiden oudeis anthrōpōn oude idein dynatai</em> (who alone has immortality, dwelling in unapproachable light, whom no human has seen or is able to see): <em>monos echōn athanasian</em> (who alone has immortality) — God\'s immortality (<em>athanasia</em>) is underived and intrinsic, not shared by creation; the angels and humans who participate in immortality do so derivatively. <em>Phōs oikōn aprositon</em> (dwelling in unapproachable light) — combines the OT theophanies of the divine glory as fire and light (Exod 24:17: consuming fire; Ps 104:2: wrapped in light as a garment; 1 Kgs 8:12: YHWH dwelling in thick darkness) with the Hellenistic philosophical tradition of the divine as pure light. <em>Hon eiden oudeis anthrōpōn</em> (whom no human has seen) — Exod 33:20 (no one may see me and live); John 1:18 (no one has seen God at any time).</p>',
    "17": '<p><em>Tois plousiois en tō nyn aiōni</em> (those who are rich in the present age): <em>en tō nyn aiōni</em> (in the present age) — the eschatological qualifier frames earthly wealth as age-specific: it belongs to the current order of things, which is passing. <em>Hypeorphroneō</em> (to be arrogant/think too highly of oneself) and <em>ēlpikenas epi ploutou adēlotēti</em> (having set hope on the uncertainty of wealth) — two linked dangers: the pride that wealth generates and the misplaced security it appears to offer. <em>Adēlotēs ploutou</em> (uncertainty/instability of wealth) — wealth as a fundamentally unreliable foundation for hope.</p>',
    "18": '<p><em>Agathoergein, ploutein en ergois kalois, eumetadotous einai, koinōnikous</em> (to do good, to be rich in good works, to be generous, to be willing to share): the four-fold instruction redirects the wealthy from passive possession to active generosity. <em>Koinōnikous</em> (willing to share, generous in sharing) — from <em>koinōnia</em> (fellowship, sharing): the wealthy are to practice the community-partnership that is the letter\'s social ideal. <em>Eumetadotous</em> (generous, liberal in giving) — <em>eu</em> (well) + <em>metadidōmi</em> (share out); the compounding emphasizes ready and generous sharing, not grudging donation.</p>',
    "19": '<p><em>Apothēsaurizonta<br>s heautois themelion kalon eis to mellon, hina epilabōntai tēs ontōs zōēs</em> (storing up for themselves a good foundation for the future, so that they may take hold of the life that is really life): <em>apothēsaurizō</em> (to store up as treasure) — the same root as <em>thēsauros</em> (treasure); the wealthy who invest in good works are making an eschatological deposit. <em>Tēs ontōs zōēs</em> (the life that really is life) — the genitive of emphasis: authentic life, contrasted with the mere biological existence of the present age. The \'taking hold\' (<em>epilabōntai</em>) mirrors the same verb applied to Timothy in v.12 (take hold of eternal life): the same eschatological grasp is available to those who invest in the kingdom rather than hoarding temporal wealth.</p>',
    "20": '<p><em>Ō Timothee, tēn parathēkēn phylaxon</em> (O Timothy, guard the deposit): <em>parathēkē</em> (deposit entrusted for safekeeping) — a banking and legal term: the deposit made with a trusted party who is responsible for returning it intact. The apostolic teaching-tradition is a deposit entrusted to Timothy; he is the custodian, not the owner. <em>Tas bebēlous kenophōnias kai antitheseis tēs pseudōnymou gnōseōs</em> (godless empty chatter and the opposing arguments of what is falsely named knowledge): <em>pseudōnymos</em> (falsely named) applied to <em>gnōsis</em> (knowledge) — the false teachers\' system is called \'knowledge\' but is falsely labeled; it lacks true knowledge. Whether this is proto-Gnosticism or a local form of Jewish esoteric speculation, the epistemological claim is refuted by the label itself.</p>',
    "21": '<p><em>Hēn tines epangellomenoi peri tēn pistin ēstochēsan</em> (which some professing have missed the mark regarding the faith): <em>ēstochēsan</em> (missed the mark, erred) — from <em>astocheō</em> (to miss the target); same verb as 1:6 (having turned aside) and 2 Tim 2:18 (who have swerved from the truth). The closing <em>hē charis meth\' hymōn</em> (grace be with you) — the standard Pauline letter-closing formula, here in the plural \'you\' (<em>hymōn</em>), indicating the letter\'s address extends beyond Timothy to the broader congregation at Ephesus.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', '1timothy')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', '1timothy', existing)

    il = json.loads((ROOT / 'data' / 'interlinear' / '1timothy.json').read_text())
    all_ok = True
    for ch in ['1', '2', '3', '4', '5', '6']:
        missing = set(il.get(ch, {}).keys()) - set(existing.get(ch, {}).keys())
        if missing:
            print(f'  ch{ch} still missing: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch{ch}: complete ({len(existing.get(ch, {}))} verses)')
    if all_ok:
        print('All 1 Tim ch6 entries present ✓')

if __name__ == '__main__':
    main()
